//-------------------------------------------------------------------------
// 조회 서브미션 성공시
//-------------------------------------------------------------------------
scwin.sbm_CertiCommon_submitDone = function (e) {
  try {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail

    let isUSD = false;
    let isKRW = false;
    let bilgAmt = 0;
    let fcrcBilgAmt = 0;
    let bilgAmtFcrc = 0;
    let spplyAmt = 0;
    let adptExchRt = 0;
    if (ds_sellingEvidence.getCellData(0, "taxnClsCd") == "01" || ds_sellingEvidence.getCellData(0, "taxnClsCd") == "04") {
      ed_wcrcDcsnClsCd.setValue("01");
      ed_wcrcDcsnClsNm.setValue("원화");
      ed_bilgAmt.setValue(ed_sumAmt.getValue());
      scwin.ed_fcrcBilgAmt = "0";
      scwin.ed_bilgAmtFcrc = "0";
      scwin.ed_crcCd = "KRW";
      ed_diffAmt.text = 0;
    } else {
      if (ds_sellingBelongContents.getTotalRow() > 0) {
        for (i = 0; i < ds_sellingBelongContents.getTotalRow(); i++) {
          if (ds_sellingBelongContents.getCellData(i, "crcCd") != "KRW") {
            if (!isUSD) {
              console.log("들어온것같고" + isUSD);
              ed_adptExchRt.setValue(Number(ds_sellingBelongContents.getCellData(i, "adptExchRt")));
              adptExchRt = ds_sellingBelongContents.getCellData(i, "adptExchRt");
              scwin.ed_crcCd = ds_sellingBelongContents.getCellData(i, "crcCd");
            }
            fcrcBilgAmt += Number(ds_sellingBelongContents.getCellData(i, "spplyAmt"));
            bilgAmtFcrc += Number(ds_sellingBelongContents.getCellData(i, "spplyAmtFcrc"));
            isUSD = true;
          } else {
            console.log("여기로왔네");
            bilgAmt += Number(ds_sellingBelongContents.getCellData(i, "spplyAmt"));
            isKRW = true;
          }
          spplyAmt += Number(ds_sellingBelongContents.getCellData(i, "spplyAmt"));
        }
        if (isUSD) {
          if (isKRW) {
            ed_wcrcDcsnClsCd.setValue("03");
            ed_wcrcDcsnClsNm.setValue("원화+외화");
          } else {
            ed_wcrcDcsnClsCd.setValue("02");
            ed_wcrcDcsnClsNm.setValue("외화");
          }
          if (adptExchRt > 0) {
            ed_diffAmt.setValue(Number(adptExchRt) * Number(bilgAmtFcrc) - Number(spplyAmt));
          } else {
            ed_diffAmt.setValue(0);
          }
        } else {
          console.log("그리곤 여기로 와야하고");
          ed_wcrcDcsnClsCd.setValue("01");
          ed_wcrcDcsnClsNm.setValue("원화");
          ed_adptExchRt.setValue(ds_sellingBelongContents.getCellData(0, "adptExchRt"));
          adptExchRt = ds_sellingBelongContents.getCellData(0, "adptExchRt");
          scwin.ed_crcCd = ds_sellingBelongContents.getCellData(0, "crcCd");
          ed_diffAmt.setValue(0);
        }
        ed_bilgAmt.setValue(bilgAmt);
        scwin.ed_fcrcBilgAmt = fcrcBilgAmt;
        scwin.ed_bilgAmtFcrc = bilgAmtFcrc;
      }
    }
    if (ds_sellingEvidence.getCellData(0, "taxnClsCd") == '03') {
      $c.gus.cfDisableObjects($p, [ica_spplyDt]);

      // WebSquare 에서는 달력 이미지를 따로 두지 않음.
      //ed_spplyDtCalendar.setValue() = '';
    }

    /*
    if(ds_single.getCellData(0, "ediClntYn") == "Y"){		
            rd_ediSndTrgtYn.Enable = "true";
        } else {
            rd_ediSndTrgtYn.Enable = "false";			
        }
    */

    //EDI전송여부 설정

    if (ds_bill.getCellData(0, "ediClntYn") == "Y") {
      rd_ediSndTrgtYn.setDisabled(false);
    } else {
      rd_ediSndTrgtYn.setDisabled(true);
    }

    // //ds_bill 데이터 수신 완료시
    // if(ds_bill.getCellData(0, "slipNp") != null && ds_bill.getCellData(0, "slipNo").length > 1){
    //     $c.gus.cfDisableBtn([bSave]);
    // } else {
    //     $c.gus.cfEnableBtnOnly([bSave]);
    // }
    // scwin.f_pushBill();

    // ds_sellingBelongContents 데이터 수신 완료시
  } catch (e) {
    console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
  }
};
