scwin.ds_sellingBelongContents_ondataload = function () {
  let rowcnt = ds_sellingBelongContents.getRowCount();
  spa_totalRows.setValue(ds_sellingBelongContents.getRowCount());
  var spplyAmt = 0;
  var spplyAmtFcrc = 0;
  var vatAmt = 0;
  var sumAmt = 0;
  if (rowcnt > 0) {
    for (i = 0; i < rowcnt; i++) {
      spplyAmt += Number(ds_sellingBelongContents.getCellData(i, "spplyAmt"));
      spplyAmtFcrc += Number(ds_sellingBelongContents.getCellData(i, "spplyAmtFcrc"));
      vatAmt += Number(ds_sellingBelongContents.getCellData(i, "vatAmt"));
    }
    ed_spplyAmt.setValue(spplyAmt);
    ed_spplyAmtFcrc.setValue(spplyAmtFcrc);
    ed_vatAmt.setValue(vatAmt);
    ed_sumAmt.setValue(spplyAmt + vatAmt);
  }
  gr_selling_belong_contents.setFocusedCell(0, 0);
};
