    ed_certiCnt.setValue(ds_sellingEvidence.getCellData(0, "certiCnt") == 0 ? ds_multi_retrieve.getRowCount() : ds_sellingEvidence.getCellData(0, "certiCnt"));
    ica_spplyDt.setValue(ds_sellingEvidence.getCellData(0, "spplyDt") == "" ? ica_confirmDt.getValue() : ds_sellingEvidence.getCellData(0, "spplyDt"));
