//-------------------------------------------------------------------------
scwin.ed_bilgExchRt_onblur = function (e) {
  var bilgExchRt = 0;
  var bilgAmt = 0;
  var bilgInscrpAmtFcrc = 0;
  if (ed_wcrcDcsnClsCd.getValue() == "01" || ed_wcrcDcsnClsCd.getValue() == "03") {
    if (ed_bilgExchRt.getValue() == "" || ed_bilgExchRt.getValue() == "0") {
      ed_bilgExchRt.setValue("0");
      ed_bilgInscrpAmtFcrc.setValue("0");
      return;
    }
    bilgExchRt = Number(ed_bilgExchRt.getValue());
    bilgAmt = Number(ed_bilgAmt.getValue());
    bilgInscrpAmtFcrc = Math.round(Number(bilgAmt) / Number(bilgExchRt) * 100) / 100;
    ed_bilgInscrpAmtFcrc.setValue(bilgInscrpAmtFcrc);
  }
};

