// scwin.btn_totalPrint2_onclick() 메소드 참조 요청
//-------------------------------------------------------------------------
scwin.f_cmaTotalPrint_onClick = async function (e) {
  if (!(await (ds_bill.getCellData(0, "lineCd") == "CMA" || ds_bill.getCellData(0, "lineCd") == "CNC" || ds_bill.getCellData(0, "lineCd") == "ANL" || ds_bill.getCellData(0, "lineCd") == "APL" || ds_bill.getCellData(0, "lineCd") == "APN" || ds_bill.getCellData(0, "lineCd") == "COS" || ds_bill.getCellData(0, "lineCd") == "PIL"))) {
    $c.win.alert($p, "CMA라인이 아닙니다.");
    return;
  }
  if (ed_certiNo.getValue().length < 1) {
    $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_049, "발행할 BILL내역"));
    return;
  }
  if (!(await $c.win.confirm($p, "발행 하시겠습니까?"))) {
    return;
  }
  //표지설정
  var oz = ds_bill.getCellData(0, "inscrpFmlaPatternCd");
  var fmlaPatternCd = ds_bill.getCellData(0, "fmlaPatternCd");
  var odi;
  var ozr;
  if ((ds_bill.getCellData(0, "lineCd") == "APL" || ds_bill.getCellData(0, "lineCd") == "CNC" || ds_bill.getCellData(0, "lineCd") == "APN") && fmlaPatternCd == "02") {
    //APL,CNC,APN 라인이고, BILL종류가 02 TS-PIER TO PIER 이면  다른 양식 사용 
    ozr = "/ds/fs/fs_202_05_21_" + oz + "_" + ds_bill.getCellData(0, "billCoverFmlaClsCd") + "N.ozr";
  } else if (ds_bill.getCellData(0, "lineCd") == "CMA" || ds_bill.getCellData(0, "lineCd") == "CNC" || ds_bill.getCellData(0, "lineCd") == "ANL" || ds_bill.getCellData(0, "lineCd") == "APN") {
    //CMA,CNC,ANL 라인은 표지에 계좌번호 출력 
    ozr = "/ds/fs/fs_202_05_21_" + oz + "_" + ds_bill.getCellData(0, "billCoverFmlaClsCd") + "2" + ".ozr";
  } else {
    ozr = "/ds/fs/fs_202_05_21_" + oz + "_" + ds_bill.getCellData(0, "billCoverFmlaClsCd") + ".ozr";
  }
  odi = "fs_202_05_21_" + oz;
  //표지odi 설정
  var bilgLodeptCd = ds_bill.getCellData(0, "bilgLodeptCd");
  var certiNo = ds_bill.getCellData(0, "certiNo");
  var type = ds_bill.getCellData(0, "billCoverFmlaClsCd");
  var dspDotYn;
  if (cbx_dspDotYn.getValue() == "1") {
    // 소수점 표시유무
    dspDotYn = "Y";
  } else {
    dspDotYn = "N";
  }
  //+ sumDcGbn

  //CERTI설정
  var ozr2 = ds_bill.getCellData(0, "upperFmlaPatternCd");
  var odi2 = "fs_202_05_21_C";
  if (ozr2 == "16") {
    odi2 = odi2 + ozr2;
  }
  //certi odi 설정
  //+certino
  var upperFmlaPatternCd = ds_bill.getCellData(0, "upperFmlaPatternCd");
  var dspTotAmt;
  //합계표시 유무
  if (cbx_dspTotAmt.getValue() == "1") {
    dspTotAmt = "Y";
  } else {
    dspTotAmt = "N";
  }
  //+ sumDcGbn

  // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
  if (ds_bill.getCellData(0, "lineCd") == "ANL" && ozr2 == "02") {
    ozr2 = "/ds/fs/fs_202_05_21_C" + ozr2 + "A" + ".ozr";
  } else if ((ds_bill.getCellData(0, "lineCd") == "ANL" || ds_bill.getCellData(0, "lineCd") == "CMA" || ds_bill.getCellData(0, "lineCd") == "APN") && ozr2 == "05") {
    ozr2 = "/ds/fs/fs_202_05_21_C" + ozr2 + "A" + ".ozr";
  } else if ((ds_bill.getCellData(0, "lineCd") == "ANL" || ds_bill.getCellData(0, "lineCd") == "CMA" || ds_bill.getCellData(0, "lineCd") == "APN") && ozr2 == "01") {
    ozr2 = "/ds/fs/fs_202_05_21_C" + ozr2 + "A" + ".ozr";
  } else if (ds_bill.getCellData(0, "lineCd") == "APL" && (ozr2 == "02" || ozr2 == "04")) {
    ozr2 = "/ds/fs/fs_202_05_21_C" + ozr2 + "P" + ".ozr";
  } else {
    ozr2 = "/ds/fs/fs_202_05_21_C" + ozr2 + ".ozr";
  }
  var data = [{
    displayName: 'report01',
    odiName: odi,
    reportName: ozr,
    odiParam: {
      bilgLodeptCd: bilgLodeptCd,
      certiNo: certiNo,
      type: type,
      dspDotYn: dspDotYn,
      sumDcGbn: scwin.sumDcGbn
    }
  }, {
    displayName: 'report02',
    odiName: odi2,
    reportName: ozr2,
    odiParam: {
      upperFmlaPatternCd: upperFmlaPatternCd,
      certiNo: certiNo,
      dspTotAmt: dspTotAmt,
      sumDcGbn: scwin.sumDcGbn
    }
  }];
  var opts = {
    type: "viewer",
    exportMode: 'viewer',
    // silent, view
    exportConfirmsave: 'false',
    printMode: 'silent',
    // silent, view
    printCopies: ed_printPage.getValue(),
    printSize: 'A5',
    // exportFilename:'DEBIS_SAMPLE_OZ_DOWNLOAD',
    // exportPath:'C:\\OZExport',
    exportFormat: 'pdf'
  };
  $c.ext.openMultiOzReport($p, data, opts);

  // let data = {
  //     ozr : ozr,
  //     odi : odi,
  //     ozr2 : ozr2,
  //     odi2 : odi2,
  //     bilgLodeptCd : bilgLodeptCd,
  //     certiNo : certiNo,
  //     type : type,
  //     dspDotYn : dspDotYn,
  //     sumDcGbn :scwin.sumDcGbn,
  //     upperFmlaPatternCd : upperFmlaPatternCd,
  //     dspTotAmt :dspTotAmt
  // }

  // let opts = {
  //     id: "fs_202_05_08p.jsp",
  //     popupName: "OZ",
  //     // modal: true,                 // 모달 여부
  //     frameModal: true,
  //     title: "Win pop",
  //     width: 910,
  //     height: 610
  // };

  // $c.win.openPopup("/ui/ds/fs/bilg/fs_202_05_08p.xml", opts, data)
};

